    "tags": [
      "Agent Workspace",
      "Forms / Lists"
    ],
    "details": "<p><strong><a href=\"https://www.servicenow.com/docs/access?context=create-crm-touchpoint&family=australia&ft:locale=en-US\" target=\"_blank\" rel=\"noopener noreferrer\">Touchpoints on CRM entities</a></strong></p>\n<p>Capture and track engagement activities for prospects and customers across communication channels such as email, phone, virtual meeting, in-person meetings, and social interactions by creating touchpoint records. Associate touchpoints with leads, opportunities, accounts, and contacts to maintain a complete engagement history.</p>",
    "link": "https://www.servicenow.com/docs/r/delta-zurich-australia/australia-zurich-accountspayableoperations-release-notes.html",
    "resources": "<a href=\"https://store.servicenow.com/store/app/5e17c41e47a7be50a342e65fe16d4333\">CRM Touchpoint</a>\n<a href=\"https://www.servicenow.com/docs/r/order-management/sales-and-order-management/order-mgt-overview.html\">Sales and Order Management Documentation</a>\n<a href=\"https://www.servicenow.com/docs/r/acct-lifecycle-events/account-lifecycle-touchpoints.html\">Touchpoints Documentation</a>\n<a href=\"https://www.servicenow.com/docs/r/acct-lifecycle-events/account-lifecycle-create-touchpoint.html\">Create a touchpoint</a>\n<a href=\"https://www.servicenow.com/community/technology-articles/engagements-in-customer-success-management/ta-p/3486278\">Engagements in Customer Success Management</a>",
