    "details": "<p><strong><a href=\"https://www.servicenow.com/docs/access?context=csm-email-interaction-record-page&family=australia&ft:locale=en-US\" target=\"_blank\" rel=\"noopener noreferrer\">Unread email count on interaction tabs</a></strong></p>\n<p>Displays the number of unread email messages on interaction tabs in CSM Configurable Workspace. Hovering over a tab displays a tooltip with a preview of the most recent email.</p>",
    "link": "https://www.servicenow.com/docs/r/delta-zurich-australia/australia-zurich-agentexperienceforcsm-release-notes.html",
    "resources": "<a href=\"https://www.servicenow.com/docs/r/customer-service-management/view-unread-email-counters-on-interaction-tabs.html\">View unread email counters on interaction tabs</a>\n<a href=\"https://www.servicenow.com/docs/r/customer-service-management/csm-interaction-record-page.html\">CSM Interaction record page</a>\n<a href=\"https://www.servicenow.com/docs/r/customer-service-management/email-as-an-interaction.html\">Email Interaction</a>\n<a href=\"https://www.servicenow.com/docs/r/customer-service-management/csm-config-workspace-set-up.html\">Set up CSM Configurable Workspace</a>",
