    "resources": "<a href=\"https://www.servicenow.com/docs/r/order-management/configuring-related-product-pricing.html\">Derived product pricing</a>\n<a href=\"https://www.servicenow.com/docs/r/order-management/create-derived-pricing-source.html\">Rules for derived pricing</a>\n<a href=\"https://www.servicenow.com/docs/r/customer-service-management/using-customer-cnt-ent-wf.html\">Using Contracts and Entitlements Workflows</a>\n<a href=\"https://store.servicenow.com/store/app/ddeae3e61b246a50a85b16db234bcb23\">Customer Contracts and Entitlements</a>",
