    "resources": "<a href=\"https://www.servicenow.com/docs/r/platform-security/data-privacy-classic/dps-data-anonymization.html\">Data Anonymization Documentation</a>\n<a href=\"https://www.servicenow.com/docs/r/platform-security/data-privacy-classic/dps-data-privacy.html\">Data Privacy Documentation</a>\n<a href=\"https://www.servicenow.com/community/developer-articles/data-privacy-anonymization-in-practice/ta-p/2574772\">Data Privacy / Anonymization in Practice</a>\n<a href=\"https://www.servicenow.com/content/dam/servicenow-assets/public/en-us/doc-type/resource-center/data-sheet/ds-servicenow-data-privacy.pdf\">ServiceNow Data Privacy Data Sheet</a>\n<a href=\"https://www.youtube.com/watch?v=CFufa44HbI0\">Platform Security | Getting started with Data Privacy</a>",
