    "resources": "<a href=\"https://www.servicenow.com/docs/r/it-service-management/digital-end-user-experience-dex/dex-appl-and-device-health.html\">DEX Application and Device Health</a>\n<a href=\"https://www.servicenow.com/docs/r/it-service-management/digital-end-user-experience-dex/user-application-metrics-cards.html\">Application performance pages</a>\n<a href=\"https://www.servicenow.com/community/dex-articles/digital-end-user-experience-dex-application-network-experience/ta-p/3190982\">Digital End-User Experience (DEX) Application Network Experience</a>\n<a href=\"https://www.youtube.com/watch?v=revglqyCyLg\">Get started with Digital End User Experience (DEX)</a>",
