    "type": "Change",
    "products": [
      "Now Assist"
    ],
    "tags": [
      "AI / Machine Learning",
      "Virtual Agent / Chatbot"
    ],
    "details": "<p><strong><a href=\"https://www.servicenow.com/docs/access?context=conversational-help-skills&family=australia&ft:locale=en-US\" target=\"_blank\" rel=\"noopener noreferrer\">Conversational Help</a></strong></p>\n<p>The discovery of Conversational Help Skills from Now Assist panel is no longer configured as auto-enabled.</p>",
    "link": "https://www.servicenow.com/docs/r/delta-zurich-australia/australia-zurich-nowassist-release-notes.html",
    "resources": "<a href=\"https://www.servicenow.com/docs/r/intelligent-experiences/now-assist-skills/conversational-help-skills.html\">Conversational Help</a>\n<a href=\"https://www.servicenow.com/docs/r/intelligent-experiences/now-assist-skills/now-assist-skills-on-by-default.html\">Now Assist skills on by default</a>\n<a href=\"https://www.servicenow.com/docs/r/intelligent-experiences/now-assist-skills/now-assist-skills.html\">Now Assist skills</a>\n<a href=\"https://www.youtube.com/watch?v=i-rL_XSn1Ro\">Now Assist Conversational Help | Overview</a>",
