    "resources": "<a href=\"https://docs.servicenow.com/bundle/zurich-customer-service-management/page/product/customer-service-management/concept/task-plan-templates.html\">Task Plan Templates</a>\n<a href=\"https://docs.servicenow.com/bundle/zurich-customer-service-management/page/product/customer-service-management/task/create-task-plan-template.html\">Create a task plan template</a>\n<a href=\"https://docs.servicenow.com/bundle/zurich-customer-service-management/page/product/customer-service-management/task/task_plan_template_configurations.html\">Create a task plan template configuration</a>\n<a href=\"https://docs.servicenow.com/bundle/zurich-customer-service-management/page/product/customer-service-management/reference/task-plan-template-access-record.html\">Task plan template access record</a>",
