    "resources": "<a href=\"https://www.servicenow.com/docs/r/order-management/explore-sales-territory-management.html\">Sales Territory Management Documentation</a>\n<a href=\"https://store.servicenow.com/store/app/01853230477d36d095ebf235126d432d\">Sales Territory Management ServiceNow Store App</a>\n<a href=\"https://www.youtube.com/watch?v=4FWRtGlsmbs\">ServiceNow Sales and Order Management (SOM) Overview</a>\n<a href=\"https://www.youtube.com/watch?v=MKsvEf3zMa0\">ServiceNow Sales & Order Management Demo</a>",
