    "resources": "<a href=\"https://store.servicenow.com/store/app/85ab6faa1b246a50a85b16db234bcb74\">Security Incident Response (ServiceNow Store)</a>\n<a href=\"https://www.servicenow.com/docs/r/security-management/security-incident-response/sir-workspace-landing-page.html\">Security Incident Response Workspace</a>\n<a href=\"https://www.servicenow.com/docs/bundle/zurich-security-management/page/product/security-incident-response/reference/sir-landing-page.html\">Security Incident Response Documentation</a>\n<a href=\"https://www.servicenow.com/products/security-incident-response.html\">Security Incident Response Product Page</a>",
