    "details": "<p><strong><a href=\"https://www.servicenow.com/docs/access?context=t_CreateResponseTask&family=australia&ft:locale=en-US\" target=\"_blank\" rel=\"noopener noreferrer\">Compose emails from Response Tasks and Investigation tabs</a></strong></p>\n<p>Send emails without having to switch tabs by composing them directly from the Response Tasks and the Investigation tabs of a security incident.</p>",
    "link": "https://www.servicenow.com/docs/r/delta-zurich-australia/australia-zurich-securityincidentresponse-release-notes.html",
    "resources": "<a href=\"https://www.servicenow.com/docs/r/security-management/security-incident-response/using-analyst-workspace.html\">Working with Security Incident Records</a>\n<a href=\"https://www.servicenow.com/docs/r/security-management/security-incident-response/explore-investigation-in-sir-workspace.html\">Explore Investigation Canvas</a>\n<a href=\"https://www.servicenow.com/docs/r/security-management/security-incident-response/security-incident-response-tasks.html\">Security Incident Response Tasks</a>\n<a href=\"https://www.servicenow.com/docs/r/security-management/security-incident-response/security-incident-response-other-records.html\">Security Incident Response Other Records</a>",
    "importance": "Low"
